// ProjectScaffold Functional Handler Conformance Tests
//
// Auto-generated by TestGen from concept spec invariants.
// Validates StorageProgram construction, purity, variant coverage,
// read/write sets, interpreted execution, and invariant conformance.

import { describe, it, expect, beforeEach } from 'vitest';
import fc from 'fast-check';
import { projectScaffoldHandler } from '../../handlers/ts/project-scaffold.handler.js';
import {
  classifyPurity,
  extractCompletionVariants,
  extractReadSet,
  extractWriteSet,
  extractPerformSet,
} from '../../runtime/storage-program.js';
import { interpret } from '../../runtime/interpreter.js';
import { createInMemoryStorage } from '../../runtime/adapters/storage.js';

describe('ProjectScaffold functional handler', () => {
  let storage: ReturnType<typeof createInMemoryStorage>;

  beforeEach(() => {
    storage = createInMemoryStorage();
  });

  describe('scaffold', () => {
    it('builds a valid StorageProgram', () => {
      const program = projectScaffoldHandler.scaffold({ name: 'test-name' });
      expect(program).toBeDefined();
      expect(program.instructions).toBeDefined();
      expect(Array.isArray(program.instructions)).toBe(true);
      expect(program.instructions.length).toBeGreaterThan(0);
    });

    it('has classifiable purity', () => {
      const program = projectScaffoldHandler.scaffold({ name: 'test-name' });
      if (!program?.instructions) return; // skip non-StorageProgram handlers
      const purity = classifyPurity(program);
      expect(['pure', 'read-only', 'read-write']).toContain(purity);
    });

    it('covers all declared variants', () => {
      const program = projectScaffoldHandler.scaffold({ name: 'test-name' });
      if (!program?.instructions) return; // skip non-StorageProgram handlers
      const variants = extractCompletionVariants(program);
      expect(variants).toContain('ok');
      expect(variants).toContain('alreadyExists');
    });

    it('declares read and write sets', () => {
      const program = projectScaffoldHandler.scaffold({ name: 'test-name' });
      if (!program?.instructions) return; // skip non-StorageProgram handlers
      const reads = extractReadSet(program);
      const writes = extractWriteSet(program);
      const purity = classifyPurity(program);
      if (purity === 'read-only') {
        expect(reads.size).toBeGreaterThan(0);
      } else if (purity === 'read-write') {
        expect(writes.size).toBeGreaterThan(0);
      }
    });

    it('has trackable transport effects', () => {
      const program = projectScaffoldHandler.scaffold({ name: 'test-name' });
      if (!program?.instructions) return; // skip non-StorageProgram handlers
      const effects = extractPerformSet(program);
      expect(effects).toBeDefined();
    });

    it('executes successfully', async () => {
      if (typeof projectScaffoldHandler.scaffold !== 'function') return;
      const result = await interpret(projectScaffoldHandler.scaffold({ name: 'test-name' }), storage);
      expect(result).toBeDefined();
      expect(result.variant).toBeDefined();
      expect(typeof result.variant).toBe('string');
    });

  });

  describe('invariant examples', () => {
    it("scaffold then duplicate fails", async () => {
      const storage = createInMemoryStorage();
      const scaffoldResult0 = await interpret(projectScaffoldHandler.scaffold({ name: {"type":"literal","value":"my-app"} }), storage);
      expect(scaffoldResult0.variant).toBe("ok");
      const project = scaffoldResult0.output["project"];
      const path = scaffoldResult0.output["path"];
      const thenResult0 = await interpret(projectScaffoldHandler.scaffold({ name: {"type":"literal","value":"my-app"} }), storage);
      expect(thenResult0.variant).toBe("alreadyExists");
    });

  });

  describe('state invariants (stateful PBT)', () => {
    it('always: projects have names and paths', async () => {
      await fc.assert(
        fc.asyncProperty(
          fc.array(
            fc.oneof(
              fc.record({ action: fc.constant('scaffold'), input: fc.record({ name: fc.string({ minLength: 1, maxLength: 20 }) }) }),
            ),
            { minLength: 1, maxLength: 5 },
          ),
          async (actionSequence) => {
            const storage = createInMemoryStorage();
            for (const step of actionSequence) {
              const actionFn = projectScaffoldHandler[step.action];
              if (typeof actionFn === 'function') {
                const program = actionFn.call(projectScaffoldHandler, step.input as Record<string, unknown>);
                const result = await interpret(program, storage);
                expect(result.variant).toBeDefined();
              }
            }
          },
        ),
        { numRuns: 50 },
      );
    });

    it('never: project without a name', async () => {
      await fc.assert(
        fc.asyncProperty(
          fc.array(
            fc.oneof(
              fc.record({ action: fc.constant('scaffold'), input: fc.record({ name: fc.string({ minLength: 1, maxLength: 20 }) }) }),
            ),
            { minLength: 1, maxLength: 5 },
          ),
          async (actionSequence) => {
            const storage = createInMemoryStorage();
            for (const step of actionSequence) {
              const actionFn = projectScaffoldHandler[step.action];
              if (typeof actionFn === 'function') {
                const program = actionFn.call(projectScaffoldHandler, step.input as Record<string, unknown>);
                const result = await interpret(program, storage);
                expect(result.variant).toBeDefined();
                // Never: project without a name
              }
            }
          },
        ),
        { numRuns: 50 },
      );
    });

  });

  describe('action contracts (PBT)', () => {
    it('scaffold requires: ', async () => {
      const storage = createInMemoryStorage();
      const result = await interpret(projectScaffoldHandler.scaffold({  }), storage);
      expect(['error', 'invalid', 'missing', 'notFound']).toContain(result.variant);
    });

    it('scaffold ensures on ok: ', async () => {
      await fc.assert(
        fc.asyncProperty(
          fc.record({ name: fc.string({ minLength: 1, maxLength: 50 }) }),
          async (input) => {
            const storage = createInMemoryStorage();
            const program = projectScaffoldHandler.scaffold(input as Record<string, unknown>);
            const result = await interpret(program, storage);
            fc.pre(result.variant === "ok");
            expect(result.output).toBeDefined();
          },
        ),
        { numRuns: 100 },
      );
    });

  });

});
